# 제출 코드
class Solution:
    def validPalindrome(self, s: str) -> bool:
        first = self.onewayChecker(s)
        second = self.onewayChecker(s[::-1])

        if first == True or second == True:
            return True
        else:
            return False

    def onewayChecker(self, s):
        end = len(s) - 1
        aaa = []
        leftIdx = 0
        rightIdx = 0

        while leftIdx <= len(s) // 2:
            if s[leftIdx] == s[end - rightIdx]:
                leftIdx += 1
                rightIdx += 1
                continue
            else:
                if len(aaa) == 0:
                    aaa.append(s[leftIdx])
                    leftIdx += 1
                else:
                    return False

        if s == s[::-1] or len(aaa) == 1:
            return True
        else:
            return False

# 테스트 데이터
sample1 = ""
sample2 = ""
sample3 = "cbbcc"
sample4 = "attbbga"
sample5 = "aba"
sample6 = "abca"

# 출력
sol = Solution()
print(sol.validPalindrome(sample1))

